6124 bool llvm::canIgnoreSignBitOfZero(const Use &U) {
6125   auto *User = cast<Instruction>(U.getUser());
6126   if (auto *FPOp = dyn_cast<FPMathOperator>(User)) {
6127     if (FPOp->hasNoSignedZeros())
6128       return true;
6129   }
6130 
6131   switch (User->getOpcode()) {
6132   case Instruction::FPToSI:
6133   case Instruction::FPToUI:
6134     return true;
6135   case Instruction::FCmp:
6136     // fcmp treats both positive and negative zero as equal.
6137     return true;
6138   case Instruction::Call:
6139     if (auto *II = dyn_cast<IntrinsicInst>(User)) {
6140       switch (II->getIntrinsicID()) {
6141       case Intrinsic::fabs:
6142         return true;
6143       case Intrinsic::copysign:
6144         return U.getOperandNo() == 0;
6145       case Intrinsic::is_fpclass:
6146       case Intrinsic::vp_is_fpclass: {
6147         auto Test =
6148             static_cast<FPClassTest>(
6149                 cast<ConstantInt>(II->getArgOperand(1))->getZExtValue()) &
6150             FPClassTest::fcZero;
6151         return Test == FPClassTest::fcZero || Test == FPClassTest::fcNone;
6152       }
6153       default:
