6200       // Other proper FP math intrinsics ignore the sign bit of NaN.
6201       case Intrinsic::maxnum:
6202       case Intrinsic::minnum:
6203       case Intrinsic::maximum:
6204       case Intrinsic::minimum:
6205       case Intrinsic::maximumnum:
6206       case Intrinsic::minimumnum:
6207       case Intrinsic::canonicalize:
6208       case Intrinsic::fma:
6209       case Intrinsic::fmuladd:
6210       case Intrinsic::sqrt:
6211       case Intrinsic::pow:
