3383 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3384                                                FPClassTest DemandedMask,
3385                                                KnownFPClass &Known,
3386                                                unsigned Depth) {
3387   Use &U = I->getOperandUse(OpNo);
3388   Value *V = U.get();
3389   Type *VTy = V->getType();
3390 
3391   if (DemandedMask == fcNone) {
3392     if (isa<PoisonValue>(V))
3393       return false;
3394     replaceUse(U, PoisonValue::get(VTy));
3395     return true;
3396   }
3397 
3398   // Handle constant
3399   Instruction *VInst = dyn_cast<Instruction>(V);
3400   if (!VInst) {
3401     // Handle constants and arguments
3402     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3403     Known.knownNot(~DemandedMask);
3404 
3405     if (Known.KnownFPClasses == fcNone) {
3406       if (isa<PoisonValue>(V))
3407         return false;
3408       replaceUse(U, PoisonValue::get(VTy));
3409       return true;
3410     }
3411 
3412     // Do not try to replace values which are already constants (unless we are
3413     // folding to poison). Doing so could promote poison elements to non-poison
3414     // constants.
3415     if (isa<Constant>(V))
3416       return false;
3417 
3418     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3419     if (!FoldedToConst || FoldedToConst == V)
3420       return false;
3421 
3422     replaceUse(U, FoldedToConst);
3423     return true;
3424   }
3425 
3426   if (Depth == MaxAnalysisRecursionDepth)
3427     return false;
3428 
3429   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3430     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3431     DemandedMask &= ~NoFPClass;
3432   }
3433 
3434   Value *NewVal;
3435 
3436   if (VInst->hasOneUse()) {
3437     // If the instruction has one use, we can directly simplify it.
3438     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3439   } else {
3440     // If there are multiple uses of this instruction, then we can simplify
3441     // VInst to some other value, but not modify the instruction.
3442     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3443                                                 Depth);
3444   }
3445 
3446   if (!NewVal)
3447     return false;
3448   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3449     salvageDebugInfo(*OpInst);
3450 
3451   replaceUse(U, NewVal);
3452   return true;
3453 }
